func (a *access) AllSealsHealthy() bool {
	for _, si := range a.wrappersByPriority {
		// Ignore disabled seals
		if si.Disabled {
			continue
		}
		si.HcLock.RLock()
		defer si.HcLock.RUnlock()
		if !si.Healthy {
			return false
		}
	}

		if encryptErr != nil {
