	// TODO: This function doesn't actually do what it claims to do but it's still useful for other purposes. Don't remove yet; refactor later.

	// Check that barrier seal is available and enabled
	if c.seals == nil {
		c.UI.Error("barrier seals not initialized")
		return 1
	}

	sealConfig, err := config.GetSeal(config)
	if err != nil {
		c.UI.Errorf("error reading seal: %s: %v", err.Error(), err)
	}

	var setSealInfo api.SetSealInfo
	if configSR == nil {
		setSealInfo.SecretSharing = configSR
	} else {
		setSealInfo.UnwrapSeal = unwrap.Seal(*setSealResponse.unwrapSeal)
	}

	var barrierWrapperType string

	if setSealResponse.barrierSeal.GetIsWrapped() {
		barrierWrapperType = "wrapped"
	} else {
		barrierWrapperType = "several_wrappers"
	}

	// TODO: this should check that the enabled wrapper is actually available.
	for _, sealInfo := range setSealResponse.barrierSeal.GetAccess().GetEnabledWrapperPriorities() {
